final:
module top_module(
    input wire [2:0] sel,
    output reg [1:0] obf_bin
    );always @ (*) begin
        case (sel)
            3'b000 : obf_bin = 2'b00;
            3'b001 : obf_bin = 2'b01;
            3'b010 : obf_bin = 2'b10;
            3'b011 : obf_bin = 2'b11;
            default : obf_bin = 2'b00;
        endcase
    end
endmodule
